import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { SeedService } from '../../../data/seed.service';
import { AuthService } from '../../../core/services/auth.service';
import { PortalRequest } from '../../../data/models';

@Component({
  selector: 'app-portal-project-requests',
  standalone: true,
  imports: [CommonModule, RouterLink, FormsModule],
  templateUrl: './portal-project-requests.component.html',
  styleUrl: './portal-project-requests.component.css',
})
export class PortalProjectRequestsComponent {
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  requests = computed<PortalRequest[]>(() =>
    this.seed.portalRequests().filter((r) => r.kind === 'project'),
  );

  modalOpen = signal(this.route.snapshot.queryParamMap.get('modal') === 'new');

  form = { name: '', scope: '', targetEnergization: '', notes: '' };

  constructor(public seed: SeedService, public auth: AuthService) {}

  statusBadge(status: PortalRequest['status']): string {
    switch (status) {
      case 'submitted': return 'badge-info';
      case 'in-review': return 'badge-warning';
      case 'quoted': return 'badge-success';
      case 'accepted': return 'badge-success';
      default: return 'badge-neutral';
    }
  }

  openModal(): void {
    this.router.navigate([], { queryParams: { modal: 'new' }, queryParamsHandling: 'merge' });
    this.modalOpen.set(true);
  }

  closeModal(): void {
    this.router.navigate([], { queryParams: { modal: null }, queryParamsHandling: 'merge' });
    this.modalOpen.set(false);
  }

  submit(): void {
    // No-op in mockup — a real submission becomes a project record for the sales team.
    this.form = { name: '', scope: '', targetEnergization: '', notes: '' };
    this.closeModal();
  }
}
